import{_ as t,o as a,c as s,a2 as r}from"./chunks/framework.Crpw6aS5.js";const g=JSON.parse('{"title":"Analytics and Insights","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/analytics.md","filePath":"en/guide/analytics.md"}'),o={name:"en/guide/analytics.md"};function i(n,e,l,c,d,h){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="analytics-and-insights" tabindex="-1">Analytics and Insights <a class="header-anchor" href="#analytics-and-insights" aria-label="Permalink to &quot;Analytics and Insights&quot;">​</a></h1><p>Nid offers analysis tools to better understand your email habits and identify cleanup opportunities.</p><hr><h2 id="activity-heatmap" tabindex="-1">Activity Heatmap <a class="header-anchor" href="#activity-heatmap" aria-label="Permalink to &quot;Activity Heatmap&quot;">​</a></h2><p>A heatmap visualizes your email activity on a <strong>day of the week × hour of the day</strong> grid. Each cell indicates the number of emails received during that time slot.</p><blockquote><p>📸 <em>Suggested screenshot: activity heatmap with days as rows and hours as columns, colored from light blue to dark blue</em></p></blockquote><p>Use this view to:</p><ul><li>Identify your peak reception times (e.g., Monday morning, Tuesday 2 PM)</li><li>Understand when you receive the most emails</li></ul><hr><h2 id="clutter-scores" tabindex="-1">Clutter Scores <a class="header-anchor" href="#clutter-scores" aria-label="Permalink to &quot;Clutter Scores&quot;">​</a></h2><p>Each sender receives a <strong>clutter score</strong> calculated from:</p><ul><li>Number of emails sent</li><li>Total email size</li><li>Number of unread emails</li><li>Read rate (read emails / total)</li><li>Presence of an unsubscribe link</li></ul><p>The higher the score, the more the sender &quot;clutters&quot; your mailbox.</p><blockquote><p>📸 <em>Suggested screenshot: clutter scores table with sender, email count, size, read rate, and score columns</em></p></blockquote><hr><h2 id="cleanup-suggestions" tabindex="-1">Cleanup Suggestions <a class="header-anchor" href="#cleanup-suggestions" aria-label="Permalink to &quot;Cleanup Suggestions&quot;">​</a></h2><p>Nid automatically generates <strong>cleanup suggestions</strong> based on the analysis of your emails:</p><table tabindex="0"><thead><tr><th>Suggestion Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Bulk senders</strong></td><td>Senders who send many emails that are rarely read</td></tr><tr><td><strong>Large senders</strong></td><td>Senders whose emails take up a lot of space</td></tr><tr><td><strong>Old newsletters</strong></td><td>Newsletters unread for a long time</td></tr><tr><td><strong>Duplicate patterns</strong></td><td>Large numbers of similar emails</td></tr></tbody></table><p>Each suggestion indicates the number of affected emails and the reclaimable space.</p><blockquote><p>📸 <em>Suggested screenshot: list of cleanup suggestions with type, description, and action buttons</em></p></blockquote><h3 id="dismiss-a-suggestion" tabindex="-1">Dismiss a Suggestion <a class="header-anchor" href="#dismiss-a-suggestion" aria-label="Permalink to &quot;Dismiss a Suggestion&quot;">​</a></h3><p>If a suggestion is not relevant, click <strong>Dismiss</strong> to hide it. It won&#39;t reappear.</p><hr><h2 id="inbox-zero-tracker" tabindex="-1">Inbox Zero Tracker <a class="header-anchor" href="#inbox-zero-tracker" aria-label="Permalink to &quot;Inbox Zero Tracker&quot;">​</a></h2><p>The <strong>Inbox Zero</strong> tracker measures your progress toward an empty inbox:</p><ul><li><strong>Email count</strong> in the inbox</li><li><strong>Unread email count</strong></li><li><strong>History</strong>: chart showing the trend over time</li></ul><blockquote><p>📸 <em>Suggested screenshot: Inbox Zero chart showing the evolution of the email count in the inbox</em></p></blockquote><p>A snapshot is automatically recorded <strong>every 6 hours</strong> to feed the history.</p><hr><h2 id="weekly-report" tabindex="-1">Weekly Report <a class="header-anchor" href="#weekly-report" aria-label="Permalink to &quot;Weekly Report&quot;">​</a></h2><p>Every <strong>Monday</strong>, a weekly report is automatically generated for each Gmail account:</p><ul><li>Number of emails received, archived, and deleted during the week</li><li>Top senders of the week</li><li>Rules executed and space freed</li><li>Comparison with the previous week</li></ul><p>The report is sent as an <strong>in-app notification</strong> and can be viewed from the <strong>Insights</strong> page.</p><blockquote><p>📸 <em>Suggested screenshot: Insights page with the weekly report (summary figures + charts)</em></p></blockquote><hr><h2 id="analytics-cache" tabindex="-1">Analytics Cache <a class="header-anchor" href="#analytics-cache" aria-label="Permalink to &quot;Analytics Cache&quot;">​</a></h2><p>Analytics data is calculated on demand and cached for <strong>15 minutes</strong> in Redis for optimal performance.</p>',37)])])}const p=t(o,[["render",i]]);export{g as __pageData,p as default};
